import React, { useState, useEffect, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { 
    Users, 
    Mail, 
    Phone, 
    MapPin, 
    Award, 
    BookOpen, 
    Calendar, 
    Linkedin, 
    Twitter, 
    Github,
    GraduationCap,
    Shield,
    Star,
    Clock,
    Building,
    User,
    X,
    UserCheck,
    Briefcase,
    Settings
} from 'lucide-react';
import '../styles/AboutPage.css';

// Import teacher images from assets
import teacher1 from '../assets/teachers/中野先生.jpg';
import teacher2 from '../assets/teachers/丸山先生.jpg';
import teacher3 from '../assets/teachers/亀山先生.jpg';
import teacher4 from '../assets/teachers/京先生.jpg';
import teacher5 from '../assets/teachers/坂口先生.jpg';
import teacher6 from '../assets/teachers/大瀧先生.jpg';

const Team = () => {
    const { t } = useTranslation();
    const [activeTab, setActiveTab] = useState('teachers');
    const [selectedMember, setSelectedMember] = useState(null);
    const [isHeroVisible, setIsHeroVisible] = useState(false);
    const heroRef = useRef(null);

    useEffect(() => {
        setIsHeroVisible(true);
        createHeroAnimatedElements();
        
        const sections = document.querySelectorAll('.about-section');
        
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                }
            });
        }, { threshold: 0.1 });
        
        sections.forEach(section => {
            observer.observe(section);
        });
        
        return () => {
            sections.forEach(section => {
                observer.unobserve(section);
            });
            
            const elements = document.querySelector('.about-hero-elements');
            if (elements) {
                while (elements.firstChild) {
                    elements.removeChild(elements.firstChild);
                }
            }
        };
    }, []);

    const createHeroAnimatedElements = () => {
        const container = document.querySelector('.about-hero-elements');
        if (!container) return;
        
        while (container.firstChild) {
            container.removeChild(container.firstChild);
        }
        
        for (let i = 0; i < 20; i++) {
            const shape = document.createElement('div');
            shape.className = 'about-shape';
            
            const shapes = ['circle', 'triangle', 'square', 'plus'];
            const shapeType = shapes[Math.floor(Math.random() * shapes.length)];
            shape.classList.add(`shape-${shapeType}`);
            
            const x = Math.random() * 100;
            const y = Math.random() * 100;
            const size = Math.random() * 30 + 10;
            const opacity = Math.random() * 0.5 + 0.1;
            const animationDelay = Math.random() * 5;
            const animationDuration = Math.random() * 20 + 10;
            
            shape.style.left = `${x}%`;
            shape.style.top = `${y}%`;
            shape.style.width = `${size}px`;
            shape.style.height = `${size}px`;
            shape.style.opacity = opacity;
            shape.style.animationDelay = `${animationDelay}s`;
            shape.style.animationDuration = `${animationDuration}s`;
            
            container.appendChild(shape);
        }
        
        const icons = ['people', 'school', 'groups', 'emoji_people', 'psychology', 'supervisor_account'];
        for (let i = 0; i < 6; i++) {
            const iconWrapper = document.createElement('div');
            iconWrapper.className = 'about-hero-icon';
            
            const x = 10 + (Math.random() * 80);
            const y = 10 + (Math.random() * 80);
            const delay = Math.random() * 5;
            
            iconWrapper.style.left = `${x}%`;
            iconWrapper.style.top = `${y}%`;
            iconWrapper.style.animationDelay = `${delay}s`;
            
            const icon = document.createElement('span');
            icon.className = 'material-icons';
            icon.textContent = icons[i % icons.length];
            
            iconWrapper.appendChild(icon);
            container.appendChild(iconWrapper);
        }
    };

    // Updated teachers data with local images
    const teachersData = [
        {
            id: 1,
            name: 'Dr. Sarah Johnson',
            title: 'Senior Web Development Instructor',
            department: 'Computer Science',
            image: teacher1,
            email: 'sarah.johnson@forumacademy.edu',
            phone: '+1 (555) 123-4567',
            location: 'New York, NY',
            experience: '8 years',
            specializations: ['React.js', 'Node.js', 'Full-Stack Development', 'UI/UX Design'],
            bio: 'Dr. Johnson is a passionate educator with over 8 years of experience in web development. She specializes in modern JavaScript frameworks and has worked with top tech companies before joining Forum Academy.',
            education: ['Ph.D. Computer Science - MIT', 'M.S. Software Engineering - Stanford'],
            achievements: ['Best Instructor Award 2023', '50+ Students Placed in Top Companies'],
            social: {
                linkedin: 'https://linkedin.com/in/sarahjohnson',
                twitter: 'https://twitter.com/sarahjohnson',
                github: 'https://github.com/sarahjohnson'
            }
        },
        {
            id: 2,
            name: 'Prof. Michael Chen',
            title: 'Data Science Lead Instructor',
            department: 'Data Science',
            image: teacher2,
            email: 'michael.chen@forumacademy.edu',
            phone: '+1 (555) 234-5678',
            location: 'San Francisco, CA',
            experience: '12 years',
            specializations: ['Machine Learning', 'Python', 'Data Analytics', 'AI Research'],
            bio: 'Professor Chen brings extensive industry and academic experience to Forum Academy. He has published numerous papers in AI and machine learning journals.',
            education: ['Ph.D. Computer Science - UC Berkeley', 'M.S. Mathematics - Caltech'],
            achievements: ['Research Excellence Award', 'Published 25+ Research Papers'],
            social: {
                linkedin: 'https://linkedin.com/in/michaelchen',
                github: 'https://github.com/michaelchen'
            }
        },
        {
            id: 3,
            name: 'Jessica Rodriguez',
            title: 'Cybersecurity Instructor',
            department: 'Cybersecurity',
            image: teacher3,
            email: 'jessica.rodriguez@forumacademy.edu',
            phone: '+1 (555) 345-6789',
            location: 'Austin, TX',
            experience: '6 years',
            specializations: ['Network Security', 'Ethical Hacking', 'Penetration Testing', 'Security Protocols'],
            bio: 'Jessica is a certified ethical hacker and security consultant who has helped secure systems for Fortune 500 companies.',
            education: ['M.S. Cybersecurity - Carnegie Mellon', 'B.S. Computer Science - UT Austin'],
            achievements: ['CISSP Certified', 'CEH Certified', 'Security Consultant of the Year 2022'],
            social: {
                linkedin: 'https://linkedin.com/in/jessicarodriguez',
                twitter: 'https://twitter.com/jessicarodriguez'
            }
        },
        {
            id: 4,
            name: 'Dr. Ahmed Hassan',
            title: 'Mobile Development Instructor',
            department: 'Mobile Technology',
            image: teacher4,
            email: 'ahmed.hassan@forumacademy.edu',
            phone: '+1 (555) 456-7890',
            location: 'Los Angeles, CA',
            experience: '9 years',
            specializations: ['React Native', 'Flutter', 'iOS Development', 'Android Development'],
            bio: 'Dr. Hassan is an expert in mobile application development with extensive experience in cross-platform solutions.',
            education: ['Ph.D. Computer Engineering - UCLA', 'M.S. Mobile Computing - USC'],
            achievements: ['Mobile Innovation Award 2022', '100+ Apps Published'],
            social: {
                linkedin: 'https://linkedin.com/in/ahmedhassan',
                github: 'https://github.com/ahmedhassan'
            }
        },
        {
            id: 5,
            name: 'Emily Watson',
            title: 'Cloud Architecture Instructor',
            department: 'Cloud Computing',
            image: teacher5,
            email: 'emily.watson@forumacademy.edu',
            phone: '+1 (555) 567-8901',
            location: 'Seattle, WA',
            experience: '7 years',
            specializations: ['AWS', 'Azure', 'Docker', 'Kubernetes', 'DevOps'],
            bio: 'Emily specializes in cloud infrastructure and DevOps practices, helping students master modern deployment strategies.',
            education: ['M.S. Cloud Computing - University of Washington', 'B.S. Information Systems - WSU'],
            achievements: ['AWS Certified Solutions Architect', 'Cloud Excellence Award 2023'],
            social: {
                linkedin: 'https://linkedin.com/in/emilywatson',
                github: 'https://github.com/emilywatson'
            }
        },
        {
            id: 6,
            name: 'Dr. Robert Kim',
            title: 'AI & Machine Learning Instructor',
            department: 'Artificial Intelligence',
            image: teacher6,
            email: 'robert.kim@forumacademy.edu',
            phone: '+1 (555) 678-9012',
            location: 'Boston, MA',
            experience: '11 years',
            specializations: ['Deep Learning', 'Neural Networks', 'Computer Vision', 'Natural Language Processing'],
            bio: 'Dr. Kim is a renowned AI researcher and educator, leading breakthrough projects in machine learning applications.',
            education: ['Ph.D. Artificial Intelligence - MIT', 'M.S. Computer Science - Harvard'],
            achievements: ['AI Research Pioneer Award', 'Published 40+ Research Papers'],
            social: {
                linkedin: 'https://linkedin.com/in/robertkim',
                github: 'https://github.com/robertkim'
            }
        }
    ];

    const adminData = [
        {
            id: 1,
            name: 'David Thompson',
            title: 'Academic Director',
            department: 'Administration',
            image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?ixlib=rb-4.0.3&auto=format&fit=crop&w=1470&h=1470&q=80',
            email: 'david.thompson@forumacademy.edu',
            phone: '+1 (555) 456-7890',
            location: 'Boston, MA',
            experience: '15 years',
            specializations: ['Educational Leadership', 'Curriculum Development', 'Strategic Planning'],
            bio: 'David oversees all academic programs at Forum Academy and ensures the highest quality of education for our students.',
            education: ['Ed.D. Educational Leadership - Harvard', 'M.B.A. - Wharton'],
            achievements: ['Excellence in Education Award', 'Led 300% Growth in Student Enrollment'],
            social: {
                linkedin: 'https://linkedin.com/in/davidthompson'
            }
        },
        {
            id: 2,
            name: 'Lisa Park',
            title: 'Student Success Manager',
            department: 'Student Services',
            image: 'https://images.unsplash.com/photo-1489424731084-a5d8b219a5bb?ixlib=rb-4.0.3&auto=format&fit=crop&w=1470&h=1470&q=80',
            email: 'lisa.park@forumacademy.edu',
            phone: '+1 (555) 567-8901',
            location: 'Seattle, WA',
            experience: '7 years',
            specializations: ['Student Support', 'Career Counseling', 'Academic Advising'],
            bio: 'Lisa is dedicated to ensuring every student achieves their academic and career goals through personalized support and guidance.',
            education: ['M.S. Student Affairs - University of Washington', 'B.A. Psychology - UCLA'],
            achievements: ['Student Advocate of the Year', '95% Student Satisfaction Rate'],
            social: {
                linkedin: 'https://linkedin.com/in/lisapark'
            }
        }
    ];
    // Add new data arrays for the additional categories
    const managementData = [
        {
            id: 1,
            name: 'Dr. Maria Santos',
            title: 'Principal / Director',
            department: 'Management',
            image: 'https://images.unsplash.com/photo-1494790108755-2616b332c8ff?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'maria.santos@forumacademy.edu',
            phone: '+1 (555) 123-0001',
            location: 'New York, NY',
            experience: '20 years',
            specializations: ['Educational Leadership', 'Strategic Planning', 'Academic Excellence', 'Institutional Management'],
            bio: 'Dr. Santos leads Forum Academy with a vision for innovative education and student success. She has transformed multiple educational institutions through strategic leadership.',
            education: ['Ed.D. Educational Leadership - Columbia University', 'M.Ed. Administration - NYU'],
            achievements: ['Educational Excellence Award 2023', 'Transformed 5+ Educational Institutions'],
            social: {
                linkedin: 'https://linkedin.com/in/mariasantos'
            }
        },
        {
            id: 2,
            name: 'James Wilson',
            title: 'Vice Principal / Academic Coordinator',
            department: 'Academic Management',
            image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'james.wilson@forumacademy.edu',
            phone: '+1 (555) 123-0002',
            location: 'Boston, MA',
            experience: '15 years',
            specializations: ['Academic Coordination', 'Curriculum Oversight', 'Faculty Management', 'Quality Assurance'],
            bio: 'James ensures academic excellence and coordinates all educational programs at Forum Academy.',
            education: ['M.Ed. Curriculum & Instruction - Harvard', 'B.A. Education - Boston University'],
            achievements: ['Academic Innovation Award', 'Led Curriculum Modernization'],
            social: {
                linkedin: 'https://linkedin.com/in/jameswilson'
            }
        }
    ];

    const careerData = [
        {
            id: 1,
            name: 'Sarah Mitchell',
            title: 'Career Services Director',
            department: 'Career Support',
            image: 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'sarah.mitchell@forumacademy.edu',
            phone: '+1 (555) 123-0003',
            location: 'San Francisco, CA',
            experience: '12 years',
            specializations: ['Career Counseling', 'Industry Partnerships', 'Job Placement', 'Professional Development'],
            bio: 'Sarah connects students with career opportunities and builds relationships with industry partners.',
            education: ['M.S. Career Counseling - UCSF', 'B.A. Psychology - Stanford'],
            achievements: ['95% Job Placement Rate', '200+ Industry Partnerships'],
            social: {
                linkedin: 'https://linkedin.com/in/sarahmitchell'
            }
        },
        {
            id: 2,
            name: 'Michael Rodriguez',
            title: 'Student Support Specialist',
            department: 'Student Support',
            image: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'michael.rodriguez@forumacademy.edu',
            phone: '+1 (555) 123-0004',
            location: 'Los Angeles, CA',
            experience: '8 years',
            specializations: ['Academic Support', 'Mental Health', 'Student Advocacy', 'Crisis Intervention'],
            bio: 'Michael provides comprehensive support to help students overcome challenges and achieve their goals.',
            education: ['M.S.W. Social Work - UCLA', 'B.A. Psychology - USC'],
            achievements: ['Student Advocate Award', 'Mental Health First Aid Certified'],
            social: {
                linkedin: 'https://linkedin.com/in/michaelrodriguez'
            }
        },
        {
            id: 3,
            name: 'Emily Chang',
            title: 'Public Relations Manager',
            department: 'Public Relations',
            image: 'https://images.unsplash.com/photo-1489424731084-a5d8b219a5bb?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'emily.chang@forumacademy.edu',
            phone: '+1 (555) 123-0005',
            location: 'Chicago, IL',
            experience: '10 years',
            specializations: ['Media Relations', 'Brand Management', 'Event Planning', 'Community Outreach'],
            bio: 'Emily manages Forum Academy\'s public image and builds strong relationships with media and community partners.',
            education: ['M.A. Communications - Northwestern', 'B.A. Journalism - University of Chicago'],
            achievements: ['PR Excellence Award', 'Increased Brand Awareness by 300%'],
            social: {
                linkedin: 'https://linkedin.com/in/emilychang',
                twitter: 'https://twitter.com/emilychang'
            }
        }
    ];

    const adminOfficeData = [
        {
            id: 1,
            name: 'Robert Johnson',
            title: 'Registrar',
            department: 'Administrative Office',
            image: 'https://images.unsplash.com/photo-1560250097-0b93528c311a?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'robert.johnson@forumacademy.edu',
            phone: '+1 (555) 123-0006',
            location: 'Austin, TX',
            experience: '14 years',
            specializations: ['Student Records', 'Enrollment Management', 'Academic Policies', 'Compliance'],
            bio: 'Robert manages all student records and ensures compliance with academic policies and regulations.',
            education: ['M.Ed. Higher Education Administration - UT Austin', 'B.A. Business Administration - Texas A&M'],
            achievements: ['Compliance Excellence Award', 'Digitized Student Records System'],
            social: {
                linkedin: 'https://linkedin.com/in/robertjohnson'
            }
        },
        {
            id: 2,
            name: 'Lisa Thompson',
            title: 'Financial Aid Advisor',
            department: 'Student Services',
            image: 'https://images.unsplash.com/photo-1494790108755-2616b332c8ff?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'lisa.thompson@forumacademy.edu',
            phone: '+1 (555) 123-0007',
            location: 'Denver, CO',
            experience: '9 years',
            specializations: ['Financial Aid', 'Scholarship Programs', 'Budget Counseling', 'Student Finance'],
            bio: 'Lisa helps students navigate financial aid options and secure funding for their education.',
            education: ['M.B.A. Finance - University of Colorado', 'B.S. Accounting - Colorado State'],
            achievements: ['Helped Secure $2M+ in Student Aid', 'Financial Literacy Program Developer'],
            social: {
                linkedin: 'https://linkedin.com/in/lisathompson'
            }
        }
    ];

    const techSupportData = [
        {
            id: 1,
            name: 'David Park',
            title: 'IT Director',
            department: 'IT Support',
            image: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'david.park@forumacademy.edu',
            phone: '+1 (555) 123-0008',
            location: 'Seattle, WA',
            experience: '16 years',
            specializations: ['Network Administration', 'Cybersecurity', 'Cloud Infrastructure', 'System Integration'],
            bio: 'David oversees all IT operations and ensures secure, reliable technology infrastructure for the academy.',
            education: ['M.S. Information Technology - University of Washington', 'B.S. Computer Science - UW'],
            achievements: ['Zero Security Breaches Record', 'Cloud Migration Excellence Award'],
            social: {
                linkedin: 'https://linkedin.com/in/davidpark',
                github: 'https://github.com/davidpark'
            }
        },
        {
            id: 2,
            name: 'Anna Kim',
            title: 'Tech Support Specialist',
            department: 'Technical Support',
            image: 'https://images.unsplash.com/photo-1489424731084-a5d8b219a5bb?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'anna.kim@forumacademy.edu',
            phone: '+1 (555) 123-0009',
            location: 'Portland, OR',
            experience: '6 years',
            specializations: ['Help Desk Support', 'Software Troubleshooting', 'User Training', 'Hardware Maintenance'],
            bio: 'Anna provides technical support to students and staff, ensuring smooth operation of all technology systems.',
            education: ['B.S. Information Systems - Portland State', 'CompTIA A+ Certified'],
            achievements: ['99% Ticket Resolution Rate', 'User Satisfaction Champion'],
            social: {
                linkedin: 'https://linkedin.com/in/annakim'
            }
        }
    ];

    const openModal = (member) => {
        setSelectedMember(member);
    };

    const closeModal = () => {
        setSelectedMember(null);
    };

    const tabs = [
        { id: 'teachers', label: t('Instructors') || '📚 Instructors', icon: GraduationCap },
        { id: 'management', label: t('Management & Support Team') || '🏫 Management & Support Team', icon: Shield },
        { id: 'career', label: t('Career Support') || '💼 Career Support', icon: Briefcase },
        { id: 'admin', label: t('Administrative Office & Student Services') || '🧾 Administrative Office & Student Services', icon: UserCheck },
        { id: 'tech', label: t('IT/Tech Support') || '🧑‍💻 IT/Tech Support', icon: Settings }
    ];



    const TeamCard = ({ member }) => (
        <div className="group relative">
            <div className="relative bg-white rounded-3xl shadow-lg border border-gray-100 overflow-hidden transition-all duration-500 hover:shadow-2xl hover:-translate-y-2 hover:scale-105">
                {/* Card Background Gradient */}
                <div className="absolute inset-0 bg-gradient-to-br from-blue-50 via-purple-50 to-pink-50 opacity-0 group-hover:opacity-100 transition-opacity duration-500"></div>
                
                {/* Image Section */}
                <div className="relative p-8 pb-4">
                    <div className="relative mx-auto w-32 h-32">
                        <img
                            src={member.image}
                            alt={member.name}
                            className="w-full h-full object-cover rounded-2xl shadow-lg border-4 border-white transition-transform duration-500 group-hover:scale-110 group-hover:rotate-3"
                            onError={(e) => {
                                e.target.src = 'https://images.unsplash.com/photo-1494790108755-2616b332c8ff?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80';
                            }}
                        />
                        <div className="absolute -inset-2 bg-gradient-to-r from-blue-500 to-purple-600 rounded-2xl opacity-0 group-hover:opacity-20 transition-opacity duration-500"></div>
                    </div>
                </div>

                {/* Content Section */}
                <div className="relative px-8 pb-8">
                    <div className="text-center mb-4">
                        <h3 className="text-xl font-bold text-gray-900 mb-2 group-hover:text-blue-700 transition-colors duration-300">
                            {member.name}
                        </h3>
                        <p className="text-blue-600 font-semibold text-sm mb-1">{member.title}</p>
                        <div className="flex items-center justify-center text-gray-500 text-sm">
                            <Building className="w-4 h-4 mr-1" />
                            {member.department}
                        </div>
                    </div>

                    {/* Quick Info */}
                    <div className="space-y-2 mb-6">
                        <div className="flex items-center justify-center text-gray-600 text-sm">
                            <MapPin className="w-4 h-4 mr-2 text-gray-400" />
                            {member.location}
                        </div>
                        <div className="flex items-center justify-center text-gray-600 text-sm">
                            <Clock className="w-4 h-4 mr-2 text-gray-400" />
                            {member.experience} experience
                        </div>
                    </div>

                    {/* Specializations */}
                    <div className="mb-6">
                        <div className="flex flex-wrap gap-2 justify-center">
                            {member.specializations.slice(0, 3).map((spec, index) => (
                                <span
                                    key={index}
                                    className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-xs font-medium border border-blue-200 group-hover:bg-blue-200 group-hover:border-blue-300 transition-colors duration-300"
                                >
                                    {spec}
                                </span>
                            ))}
                            {member.specializations.length > 3 && (
                                <span className="px-3 py-1 bg-gray-100 text-gray-600 rounded-full text-xs font-medium">
                                    +{member.specializations.length - 3}
                                </span>
                            )}
                        </div>
                    </div>

                    {/* Action Buttons */}
                    <div className="flex items-center justify-between">
                        <div className="flex space-x-2">
                            {member.social?.linkedin && (
                                <a
                                    href={member.social.linkedin}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="p-2 bg-gray-100 text-gray-600 rounded-lg hover:bg-blue-100 hover:text-blue-600 transition-colors duration-300"
                                >
                                    <Linkedin className="w-4 h-4" />
                                </a>
                            )}
                            {member.social?.github && (
                                <a
                                    href={member.social.github}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="p-2 bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-800 hover:text-white transition-colors duration-300"
                                >
                                    <Github className="w-4 h-4" />
                                </a>
                            )}
                            <a
                                href={`mailto:${member.email}`}
                                className="p-2 bg-gray-100 text-gray-600 rounded-lg hover:bg-green-100 hover:text-green-600 transition-colors duration-300"
                            >
                                <Mail className="w-4 h-4" />
                            </a>
                        </div>
                        
                        <button
                            onClick={() => openModal(member)}
                            className="px-4 py-2 bg-gradient-to-r from-blue-500 to-purple-600 text-white rounded-lg font-medium hover:from-blue-600 hover:to-purple-700 transition-all duration-300 transform hover:scale-105 shadow-md hover:shadow-lg"
                        >
                            View Profile
                        </button>
                    </div>
                </div>

                {/* Hover Overlay Effect */}
                <div className="absolute inset-0 border-2 border-transparent group-hover:border-blue-200 rounded-3xl transition-colors duration-500"></div>
            </div>
        </div>
    );

    return (
        <div className="about-page">
            {/* Hero Section */}
            <section 
                ref={heroRef}
                className={`about-hero ${isHeroVisible ? 'visible' : ''}`}
            >
                <div className="about-hero-bg">
                    <div className="about-hero-elements"></div>
                    <div className="about-glow about-glow-1"></div>
                    <div className="about-glow about-glow-2"></div>
                </div>
                
                <div className="container">
                    <div className="about-hero-content">
                        <div className="about-hero-badge">
                            <span className="material-icons">people</span>
                            {t('team.hero.badge') || 'Meet Our Experts'}
                        </div>
                        
                        <h1 className="about-hero-title">
                            {t('team.hero.title') || 'Our Professional'} <span className="highlight-text">{t('team.hero.highlight') || 'Team'}</span>
                        </h1>
                        
                        <p className="about-hero-description">
                            {t('team.hero.description') || 'Meet the passionate educators and administrators who make Forum Academy a world-class institution for technology education and career development.'}
                        </p>
                        
                        <div className="about-hero-stats">
                            <div className="stat-item">
                                <div className="stat-number">50+</div>
                                <div className="stat-label">{t('team.stats.experts') || 'Expert Instructors'}</div>
                            </div>
                            <div className="stat-item">
                                <div className="stat-number">15+</div>
                                <div className="stat-label">{t('team.stats.experience') || 'Years Experience'}</div>
                            </div>
                            <div className="stat-item">
                                <div className="stat-number">95%</div>
                                <div className="stat-label">{t('team.stats.satisfaction') || 'Student Satisfaction'}</div>
                            </div>
                            <div className="stat-item">
                                <div className="stat-number">100+</div>
                                <div className="stat-label">{t('team.stats.certifications') || 'Certifications'}</div>
                            </div>
                        </div>
                        
                        <div className="about-hero-actions">
                            <a href="#team-members" className="btn btn-primary">{t('team.hero.meetTeam') || 'Meet Our Team'}</a>
                            <a href="/contact" className="btn btn-outline">{t('team.hero.joinUs') || 'Join Our Team'}</a>
                        </div>
                    </div>
                </div>
                
                <div className="scroll-indicator">
                    <a href="#team-members">
                        <span>{t('team.hero.exploreTeam') || 'Explore Our Team'}</span>
                        <span className="material-icons">keyboard_arrow_down</span>
                    </a>
                </div>
            </section>

            {/* Team Section */}
            <section id="team-members" className="about-section py-20 bg-gradient-to-br from-gray-50 to-blue-50">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    {/* Section Header */}
                    <div className="text-center mb-16">
                        <h2 className="text-4xl font-bold text-gray-900 mb-4">
                            Meet Our <span className="text-blue-600">Amazing Team</span>
                        </h2>
                        <p className="text-lg text-gray-600 max-w-3xl mx-auto">
                            Our dedicated team of professionals brings years of industry experience and passion for education to help you succeed in your learning journey.
                        </p>
                    </div>

                    {/* Tab Navigation */}
                    <div className="flex justify-center mb-12">
                        <div className="bg-white rounded-2xl p-2 shadow-lg border border-gray-200">
                            <div className="flex space-x-2">
                                {tabs.map((tab) => {
                                    const IconComponent = tab.icon;
                                    return (
                                        <button
                                            key={tab.id}
                                            onClick={() => setActiveTab(tab.id)}
                                            className={`flex items-center space-x-2 px-6 py-3 rounded-xl font-medium transition-all duration-300 ${
                                                activeTab === tab.id
                                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg transform scale-105'
                                                    : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'
                                            }`}
                                        >
                                            <IconComponent className="w-5 h-5" />
                                            <span>{tab.label}</span>
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    </div>

                    {/* Team Grid */}
                    {/* <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {(activeTab === 'teachers' ? teachersData : adminData).map((member) => (
                            <TeamCard key={member.id} member={member} />
                        ))}
                    </div> */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {(() => {
                            switch(activeTab) {
                                case 'teachers':
                                    return teachersData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                case 'management':
                                    return managementData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                case 'career':
                                    return careerData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                case 'admin':
                                    return adminOfficeData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                case 'tech':
                                    return techSupportData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                default:
                                    return teachersData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                }
                        })()}
                    </div>
                </div>
            </section>

            {/* Team Modal */}
            {selectedMember && (
                <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
                    <div className="bg-white rounded-2xl max-w-4xl w-full max-h-[90vh] overflow-y-auto">
                        <div className="relative">
                            <div className="h-64 bg-gradient-to-r from-blue-500 to-purple-600 relative overflow-hidden">
                                <div className="absolute inset-0 bg-black/20"></div>
                                <button
                                    onClick={closeModal}
                                    className="absolute top-4 right-4 p-2 bg-white/20 backdrop-blur-sm rounded-lg hover:bg-white/30 transition-colors duration-300 text-white"
                                >
                                    <X className="w-6 h-6" />
                                </button>
                                <div className="absolute bottom-6 left-6 right-6">
                                    <div className="flex items-end space-x-6">
                                        <img
                                            src={selectedMember.image}
                                            alt={selectedMember.name}
                                            className="w-24 h-24 rounded-2xl border-4 border-white shadow-lg object-cover"
                                        />
                                        <div className="text-white flex-1">
                                            <h2 className="text-3xl font-bold mb-1">{selectedMember.name}</h2>
                                            <p className="text-blue-100 text-lg">{selectedMember.title}</p>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="p-8">
                                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                                    {/* Main Content */}
                                    <div className="lg:col-span-2 space-y-6">
                                        <div>
                                            <h3 className="text-xl font-bold text-gray-900 mb-3 flex items-center">
                                                <User className="w-5 h-5 mr-2 text-blue-600" />
                                                About
                                            </h3>
                                            <p className="text-gray-600 leading-relaxed">{selectedMember.bio}</p>
                                        </div>

                                        <div>
                                            <h3 className="text-xl font-bold text-gray-900 mb-3 flex items-center">
                                                <BookOpen className="w-5 h-5 mr-2 text-blue-600" />
                                                Specializations
                                            </h3>
                                            <div className="flex flex-wrap gap-2">
                                                {selectedMember.specializations.map((spec, index) => (
                                                    <span key={index} className="px-3 py-1 bg-blue-100 text-blue-600 rounded-full text-sm font-medium">
                                                        {spec}
                                                    </span>
                                                ))}
                                            </div>
                                        </div>

                                        <div>
                                            <h3 className="text-xl font-bold text-gray-900 mb-3 flex items-center">
                                                <GraduationCap className="w-5 h-5 mr-2 text-blue-600" />
                                                Education
                                            </h3>
                                            <ul className="space-y-2">
                                                {selectedMember.education.map((edu, index) => (
                                                    <li key={index} className="flex items-start space-x-2">
                                                        <div className="w-2 h-2 bg-blue-600 rounded-full mt-2 flex-shrink-0"></div>
                                                        <span className="text-gray-600">{edu}</span>
                                                    </li>
                                                ))}
                                            </ul>
                                        </div>

                                        <div>
                                            <h3 className="text-xl font-bold text-gray-900 mb-3 flex items-center">
                                                <Award className="w-5 h-5 mr-2 text-blue-600" />
                                                Achievements
                                            </h3>
                                            <ul className="space-y-2">
                                                {selectedMember.achievements.map((achievement, index) => (
                                                    <li key={index} className="flex items-start space-x-2">
                                                        <Star className="w-4 h-4 text-yellow-500 mt-0.5 flex-shrink-0" />
                                                        <span className="text-gray-600">{achievement}</span>
                                                    </li>
                                                ))}
                                            </ul>
                                        </div>
                                    </div>

                                    {/* Sidebar */}
                                    <div className="space-y-6">
                                        <div className="bg-gray-50 rounded-xl p-6">
                                            <h3 className="font-bold text-gray-900 mb-4">Contact Information</h3>
                                            <div className="space-y-3">
                                                <div className="flex items-center space-x-3">
                                                    <Mail className="w-4 h-4 text-gray-400" />
                                                    <a href={`mailto:${selectedMember.email}`} className="text-blue-600 hover:text-blue-700">
                                                        {selectedMember.email}
                                                    </a>
                                                </div>
                                                <div className="flex items-center space-x-3">
                                                    <Phone className="w-4 h-4 text-gray-400" />
                                                    <span className="text-gray-600">{selectedMember.phone}</span>
                                                </div>
                                                <div className="flex items-center space-x-3">
                                                    <MapPin className="w-4 h-4 text-gray-400" />
                                                    <span className="text-gray-600">{selectedMember.location}</span>
                                                </div>
                                                <div className="flex items-center space-x-3">
                                                    <Clock className="w-4 h-4 text-gray-400" />
                                                    <span className="text-gray-600">{selectedMember.experience} experience</span>
                                                </div>
                                            </div>
                                        </div>

                                        {/* Social Links */}
                                        {selectedMember.social && (
                                            <div className="bg-gray-50 rounded-xl p-6">
                                                <h3 className="font-bold text-gray-900 mb-4">Connect</h3>
                                                <div className="flex space-x-3">
                                                    {selectedMember.social.linkedin && (
                                                        <a 
                                                            href={selectedMember.social.linkedin} 
                                                            target="_blank" 
                                                            rel="noopener noreferrer"
                                                            className="p-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors duration-300"
                                                        >
                                                            <Linkedin className="w-5 h-5" />
                                                        </a>
                                                    )}
                                                    {selectedMember.social.twitter && (
                                                        <a 
                                                            href={selectedMember.social.twitter} 
                                                            target="_blank" 
                                                            rel="noopener noreferrer"
                                                            className="p-2 bg-blue-400 text-white rounded-lg hover:bg-blue-500 transition-colors duration-300"
                                                        >
                                                            <Twitter className="w-5 h-5" />
                                                        </a>
                                                    )}
                                                    {selectedMember.social.github && (
                                                        <a 
                                                            href={selectedMember.social.github} 
                                                            target="_blank" 
                                                            rel="noopener noreferrer"
                                                            className="p-2 bg-gray-800 text-white rounded-lg hover:bg-gray-900 transition-colors duration-300"
                                                        >
                                                            <Github className="w-5 h-5" />
                                                        </a>
                                                    )}
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Team;
